配置功能Config可以使用RestAssured内建的方法，进行全局的配置，有如下的方法： 12345RestAssured.baseURI = "https://api.github.com";RestAssured.authentication = oauth2("token");RestAssured.authentication = preemptive().basic("xxxx", "xxx");RestAssured.port = 443;RestAssured.basePath = "/user"; 除了以上的配置，也可以使用RestAssured提供的配置功能进行实现，以下查看RestAssured提供的丰富的配置功能： 我们已经看到RestAssured提供丰富的配置实现，以下我们看下两个具体配置实体 使用headerConfig重写的方法，对header参数进行覆盖处理 1234567891011121314151617181920212223/** * Header配置实例 */@Testvoid headerConfig() { // 使用headerConfig重写的方法，对test的header参数进行覆盖处理 RestAssured.config = RestAssured.config().headerConfig(HeaderConfig.headerConfig().overwriteHeadersWithName("test")); String loginBody = "{
" + " "username":"xiaohong",
" + " "password":"123123"
" + "}"; given() .log().all() .contentType(ContentType.JSON) .header("test", "aaa") .header("test", "bbb") .body(loginBody) .when() .get("/user/login") .then() .log() .body().statusCode(200);} 使用logConfig的enablePrettyPrinting设置为false，响应返回body则不会进行格式化显示 12345678910111213141516171819202122/** * Log配置实例 */@Testvoid logConfig() { // 使用logConfig的enablePrettyPrinting设置为false，响应返回body则不会进行格式化显示 RestAssured.config = RestAssured.config().logConfig(LogConfig.logConfig().enablePrettyPrinting(false)); String loginBody = "{
" + " "username":"xiaohong",
" + " "password":"123123"
" + "}"; given() .log().all() .contentType(ContentType.JSON) .body(loginBody) .when() .get("/user/login") .then() .log() .body().statusCode(200);} 模板功能Specification我们在写接口测试的时候，在很多情况下我们会针对某些特定的接口写出大量的测试用例，而这些接口的请求和响应判断当中往往会有重复的内容定义，除了使用之前定义的通用配置，也可以使用RestAssured提供的模板功能来定义接口的请求和响应，在多个测试用例中使用，减少重复的测试代码编写。 常用的就是RequestSpecification和ResponseSpecification。 12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152535455565758package com.api.demo;import io.restassured.RestAssured;import io.restassured.builder.RequestSpecBuilder;import io.restassured.builder.ResponseSpecBuilder;import io.restassured.http.ContentType;import io.restassured.specification.RequestSpecification;import io.restassured.specification.ResponseSpecification;import org.junit.jupiter.api.BeforeAll;import org.junit.jupiter.api.Test;import static io.restassured.RestAssured.given;/** * @author jingLv * @date 2021/01/04 */public class TestSpecification { private static String token; private static RequestSpecification requestSpecification; private static ResponseSpecification responseSpecification; @BeforeAll static void setUp() { RestAssured.baseURI = "http://localhost:8886/v1"; // 请求模板构造类，构造请求实例 RequestSpecBuilder requestSpecBuilder = new RequestSpecBuilder(); requestSpecBuilder.setContentType(ContentType.JSON); requestSpecification = requestSpecBuilder.build(); // 响应模板构造类，构造响应实例 ResponseSpecBuilder responseSpecBuilder = new ResponseSpecBuilder(); responseSpecBuilder.expectStatusCode(200); responseSpecification = responseSpecBuilder.build(); } /** * 使用模板功能来简化测试用例编写 */ @Test void testLogin() { String loginBody = "{
" + " "username":"xiaohong",
" + " "password":"123123"
" + "}"; given() .log().all() .spec(requestSpecification) .body(loginBody) .when() .get("/user/login") .then() .spec(responseSpecification) .log(); }} 过滤功能Filter请求与响应内容的修改过滤功能是指在请求发出之前，或者响应接收到之前，能够通过Filter过滤器，可以改变请求或者响应的内容。特别是使用了大量的模板功能的时候，需要对个别的用例进行微调，这是就可以通过Filter进行实现。 以下示例进行Request与Response的使用Filter进行修改 123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384package com.api.demo;import io.restassured.RestAssured;import io.restassured.builder.RequestSpecBuilder;import io.restassured.builder.ResponseBuilder;import io.restassured.builder.ResponseSpecBuilder;import io.restassured.response.Response;import io.restassured.specification.RequestSpecification;import io.restassured.specification.ResponseSpecification;import org.junit.jupiter.api.BeforeAll;import org.junit.jupiter.api.Test;import static io.restassured.RestAssured.given;/** * @author jingLv * @date 2021/01/04 */public class TestFilter { private static String token; private static RequestSpecification requestSpecification; private static ResponseSpecification responseSpecification; @BeforeAll static void setUp() { RestAssured.baseURI = "http://localhost:8886/v1"; String loginBody = "{
" + " "username":"xiaohong",
" + " "password":"123123"
" + "}"; // 请求模板构造类，构造请求实例 RequestSpecBuilder requestSpecBuilder = new RequestSpecBuilder(); requestSpecBuilder.setBody(loginBody); requestSpecification = requestSpecBuilder.build(); // 响应模板构造类，构造响应实例 ResponseSpecBuilder responseSpecBuilder = new ResponseSpecBuilder(); responseSpecBuilder.expectStatusCode(200); responseSpecification = responseSpecBuilder.build(); } /** * 利用Filter过滤器实现request请求的修改 */ @Test void testLoginRequest() { given() .filter((filterableRequestSpecification, filterableResponseSpecification, filterContext) -&gt; { String loginBody = "{
" + " "username":"xiaohei",
" + " "password":"123123"
" + "}"; // 修改ContentType的类型 filterableRequestSpecification.body(loginBody); return filterContext.next(filterableRequestSpecification, filterableResponseSpecification); }) .log().all() .spec(requestSpecification) .when() .get("/user/login") .then() .spec(responseSpecification) .log(); } /** * 利用Filter过滤器实现response请求的修改 */ @Test void testLoginResponse() { Response response = given() .log().all() .spec(requestSpecification) .when() .get("/user/login"); Response newResponse = new ResponseBuilder().clone(response) .setBody("这是一个修改的Response").build(); newResponse.then() .spec(responseSpecification) .log().all(); }} Filter机制rest-assured的Filter 过滤器会在请求实际发起之前侦测和改变该请求的内容，也可以在响应体实际返回之前拦截并改变。您可以将其理解为AOP中的around advice（译者注：可以自行搜索切片编程）。过滤器也可以用在认证scheme、session管理、日志中。创建一个过滤器需要实现io.restassured.filter.Filter接口。 rest-assured提供了几个过滤器： io.restassured.filter.log.RequestLoggingFilter: 可以打印出请求模式的细节。 io.restassured.filter.log.ResponseLoggingFilter: 可以打印响应信息的细节如果响应体的状态码匹配given方法的参数。 io.restassured.filter.log.ErrorLoggingFilter: 如果发生了异常（状态码在400和500之间），过滤器将会打印响应的内容。 利用filter机制实现自动解密 filter可以应用于所有全局请求 request处理 记录所有的request数据 自动填充token response处理 重新构建新的response filter((req,res,ctx))-&gt;{//重新生成response} new ResponseBuilder().clone(originalResponse) 修改request 可以修改请求内容 自动带上cookie 通用的请求数据记录 记录所有的请求和响应 接口加解密处理以base64加解密过程为例 原始内容 -&gt; 加密内容 加密内容 -&gt; internet -&gt; response -&gt; client client -&gt; filter -&gt; 解密内容 body正常断言 示例 WireMock模拟一个接口，返回的主体为Base64加密 Filter机制，编写测试代码 1234567891011121314151617181920212223242526/** * 使用filter处理请求返回body加密的情况 */@Testvoid testEncode() { given().baseUri("http://localhost:9090") .log().all() .filter((request, response, context) -&gt; { // 发送原始请求，但是返回的Response不具备set方法，无法修改body Response resOrigin = context.next(request, response); // 解密过程 String raw = Base64.decodeStr(resOrigin.body().asString()); // 响应构造器，ResponseBuilder的作用主要是在Response的基础上建设出来一个新的可以修改的body对象（克隆出来一个新的） ResponseBuilder resBuilder = new ResponseBuilder().clone(resOrigin); //Response无法直接修改body，所有间接的通过ResponseBuilder构建 resBuilder.setBody(raw); //ResponseBuilder在最后通过build方法直接创建一个用于返回的不可修改的Response return resBuilder.build(); }) .when() .get("/api/encryption").prettyPeek() .then() .log().all() .body("books.name[0]", equalTo("西游记")) .statusCode(200);} 执行结果 如果是所有接口都需要加解密处理呢？我们可以使用RestAssured配置功能，全局添加 123456789101112131415161718192021222324/** * 全局抽出来的filter对象 */ @BeforeAll static void before() { RestAssured.filters((req, res, ctx) -&gt; { // 添加过滤接口路径，包含就处理加解密过程，如果不包含就不进行处理 if (req.getURI().contains("/api/encryption")) { // 返回的Response不具备set方法，无法修改body Response resOrigin = ctx.next(req, res); // 解密过程 String raw = Base64.decodeStr(resOrigin.body().asString()); // 响应构造器，ResponseBuilder的作用主要是在Response的基础上建设出来一个新的可以修改的body对象 ResponseBuilder resBuilder = new ResponseBuilder().clone(resOrigin); //Response无法直接修改body，所有间接的通过ResponseBuilder构建 resBuilder.setBody(raw); //ResponseBuilder在最后通过build方法直接创建一个用于返回的不可修改的Response return resBuilder.build(); } else { return ctx.next(req, res); } } ); } Session Filter sessionIdName sessionId session filter可以自动从请求中提取sessionId，并在以后的请求中再附带进cookie发送出去 示例以Jenkins模拟登录，获取Session，请求其他的接口 根据获取到的信息，编写代码 12345678910111213141516171819@Test void testJenkinsLogin() { RestAssured.config = RestAssured.config().sessionConfig( new SessionConfig().sessionIdName("JSESSIONID.7ef748a1")); SessionFilter sessionFilter = new SessionFilter(); given().log().all() .filter(sessionFilter) .queryParam("j_password", "xxxx") .queryParam("Submit", "登录") .queryParam("j_username", "xxxx") .when().post("http://xx.xxx.xxx.xx:8080/j_acegi_security_check") .then() .statusCode(302); given().log().all().filter(sessionFilter) .when().get("http://xx.xxx.xxx.xx:8080/job/xxxx/").prettyPeek() .then().statusCode(200); }
